import { CommonModule } from '@angular/common';
import {
  ChangeDetectorRef,
  Component,
  DestroyRef,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  AssetResponse,
  AssetMoveRequest,
  ClientListItem,
  AccountsService,
} from '../../../../../api';
import {
  hasProperty,
  isDefined,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import {
  createAutocompleteField,
  createDropdownField,
  FormAction,
  FormFieldConfig,
} from '../../../../../shared/models';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import {
  Subject,
  debounceTime,
  switchMap,
  of,
  catchError,
  from,
  concatMap,
} from 'rxjs';
import { UtilityService } from '../../../../../core/services/utility.service';
import { SEARCH_DEBOUNCE_TIME } from '../../../../../core/models';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-move-form',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    DynamicFormComponent,
    TranslatePipe,
  ],
  templateUrl: './asset-move-form.component.html',
  styleUrl: './asset-move-form.component.scss',
})
export class AssetMoveFormComponent implements OnInit {
  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly utilityService = inject(UtilityService);
  private readonly accountsService = inject(AccountsService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  protected readonly translate = inject(TranslateService);

  ownerId: string | null = null;
  assetIds: string[] = [];
  protected formFields: FormFieldConfig[] = [];
  clientsSearchResults = signal<ClientListItem[] | undefined>(undefined);
  private readonly searchSubject = new Subject<string>();
  private readonly cdr = inject(ChangeDetectorRef);
  protected actions: FormAction[] = this.buildDefaultActions();

  constructor() {
    effect(() => {
      const searchResults = this.clientsSearchResults();
      const field = this.formFields.find(
        (f) => f.key === 'destinationClientId',
      );
      if (field?.props) {
        // Update the suggestions
        field.props = {
          ...field.props,
          suggestions: searchResults,
        };
      }
      this.cdr.detectChanges();
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      this.assetIds = this.dialogConfig.data.assetIds ?? [];
    }
    this.formFields = [
      createAutocompleteField(
        'destinationClientId',
        this.translate.instant('ADMIN.ASSETS.MOVE.FIELDS.DESTINATION_CLIENT'),
        [],
        this.clientsSearchResults(),
        this.searchClient.bind(this),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'destinationClientId',
          props: {
            appendTo: 'body',
            showClear: true,
            multiple: false,
            field: 'name',
            completeOnFocus: false,
            typeahead: true,
            showEmptyMessage: true,
            emptyMessage: this.translate.instant(
              'SHARED.CLIENT_SELECTION_FORM',
              {
                count: 0,
              },
            ),
          },
        },
      ),
      createDropdownField(
        'includeDevice',
        this.translate.instant('ADMIN.ASSETS.MOVE.FIELDS.INCLUDE_DEVICE'),
        [
          {
            label: this.translate.instant('SHARED.COMMON.FORMS.CHECKBOX.YES'),
            value: true,
          },
          {
            label: this.translate.instant('SHARED.COMMON.FORMS.CHECKBOX.NO'),
            value: false,
          },
        ],
        true,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'includeDevice',
          props: {
            appendTo: 'body',
          },
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ASSETS.MOVE.FIELDS.INCLUDE_DEVICE',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createDropdownField(
        'includeSimCard',
        this.translate.instant('ADMIN.ASSETS.MOVE.FIELDS.INCLUDE_SIMCARD'),
        [
          {
            label: this.translate.instant('SHARED.COMMON.FORMS.CHECKBOX.YES'),
            value: true,
          },
          {
            label: this.translate.instant('SHARED.COMMON.FORMS.CHECKBOX.NO'),
            value: false,
          },
        ],
        true,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'includeSimCard',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
    this.setUpClientsSearch();
  }

  protected buildDefaultActions(): FormAction[] {
    return [
      {
        label: this.translate.instant('SHARED.COMMON.BUTTONS.CANCEL'),
        action: () => this.onCancel(),
        severity: 'secondary',
      },
      {
        label: this.translate.instant('SHARED.COMMON.BUTTONS.OK'),
        action: (formData: FormGroup) => {
          const value = {
            ...formData.value,
            destinationClientId: formData.value['destinationClientId']?.id,
          };
          this.onWizardComplete(value as AssetMoveRequest);
        },
        severity: 'primary',
        disabled: (form?: FormGroup) => {
          if (isNullOrUndefined(form)) return true;
          return form.pristine || form.invalid;
        },
      },
    ];
  }

  private setUpClientsSearch(): void {
    this.searchSubject
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          const trimmedSearchTerm = searchTerm.trim();

          if (trimmedSearchTerm.length === 0) {
            return of({ items: [] });
          }

          const filters = {
            state: { value: 'active', operator: '=' },
            name: { value: `*${trimmedSearchTerm}*`, operator: '=' },
          };
          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.accountsService
            .listClients(this.ownerId ?? '', 0, 10, 'name', rqlFilter)
            .pipe(
              catchError(() => {
                return of({ items: [] });
              }),
            );
        }),
      )
      .subscribe({
        next: (data) => {
          if (isDefined(data) && hasProperty(data, 'items')) {
            this.clientsSearchResults.set(
              isNullOrUndefined(data.items) ? [] : data.items,
            );
          }
        },
        error: () => {
          this.clientsSearchResults.set([]);
        },
      });
  }

  searchClient(searchTerm: string) {
    this.clientsSearchResults.set(undefined);
    this.searchSubject.next(searchTerm);
  }

  onWizardComplete(context: AssetMoveRequest): void {
    if (this.assetIds.length === 0) return;

    from(this.assetIds)
      .pipe(
        concatMap((id) => this.entitiesService.moveAsset(id, context)),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe({
        next: (response: AssetResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            operation: 'update',
            entityId: response.id,
          });
        },
        complete: () => this.dialogRef.close(),
        error: () => {},
      });
  }

  // Update cancel to close dialog with no result
  onCancel(): void {
    this.dialogRef.close();
  }
}
